SELECT 
FROM ems_carbon_verification_activity

    AND year = #{year}
    AND org_unit = #{orgUnit}

        AND emission_source LIKE CONCAT('%', #{emissionSource}, '%')


ORDER BY emission_source, month

SELECT 
FROM ems_carbon_verification_activity
WHERE year = #{year}
AND org_unit = #{orgUnit}
AND emission_source = #{emissionSource}
ORDER BY month

SELECT 
FROM ems_carbon_verification_activity
WHERE year = #{year}
AND org_unit = #{orgUnit}
ORDER BY emission_source, month

SELECT 
FROM ems_carbon_verification_activity
WHERE year = #{year} AND month = #{month}
  AND emission_source = #{emissionSource}
  AND org_unit = #{orgUnit}
LIMIT 1
